ark:border-zinc-600'}`}>{isChecked && <Check size={12}/>}</div><span className={`text-sm ${isChecked ? 'text-zinc-500 line-through' : 'text-zinc-700 dark:text-zinc-300'}`}>{topic.name}</span></div>); })}</div></div>); })}</div>
