                          </div>
                      </button>
                  </div>

                  <button 
                      onClick={() => setTaskToComplete(null)}
                      className="mt-8 text-zinc-600 hover:text-red-500 text-xs font-bold uppercase tracking-widest w-full text-center transition-colors"
                  >
                      Cancelar Relatório
                  </button>
              </div>
          </div>
      )}
    </div>
  );
};

