                    <button type="button" onMouseDown={(e) => { e.preventDefault(); execCmd('fontSize', '2'); }} className="p-1.5 hover:bg-zinc-200 dark:hover:bg-zinc-700 rounded" title="Diminuir"><Minus size={16}/></button>
