// Simple Login Component
const LoginScreen = ({ onLogin }: { onLogin: (u: User) => void }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isRegistering, setIsRegistering] = useState(false);
  const [name, setName] = useState('');

  const handleLogin = async () => {
    const users = await globalRepo.getUsers();
    // Admin backdoor for demo or check against DB
    const user = users.find(u => u.email === email && u.password === password);
    if (user) {
      if (!user.approved) return alert('Sua conta ainda não foi aprovada pelo comando.');
      onLogin(user);
    } else {
      alert('Credenciais inválidas.');
    }
  };

  const handleRegister = async () => {
      const users = await globalRepo.getUsers();
      if(users.find(u => u.email === email)) return alert("Email já cadastrado");

      const newUser: User = {
          id: Date.now().toString(),
          name,
          email,
          password,
          role: UserRole.STUDENT,
          approved: false, // Requires admin approval
          achievements: []
      };
      await globalRepo.saveUser(newUser);
      alert("Solicitação enviada! Aguarde aprovação do comando.");
      setIsRegistering(false);
  };

  return (
    <div className="min-h-screen bg-[#09090b] flex items-center justify-center p-4">
      <div className="bg-zinc-900 p-8 rounded-xl border border-zinc-800 w-full max-w-md">
        <h1 className="text-2xl font-black text-white uppercase text-center mb-6">Sangue <span className="text-red-600">Milico</span></h1>
        <div className="space-y-4">
            {isRegistering && <input placeholder="Nome de Guerra" className="w-full bg-zinc-950 border border-zinc-800 p-3 rounded text-white" value={name} onChange={e => setName(e.target.value)} />}
            <input placeholder="Email" className="w-full bg-zinc-950 border border-zinc-800 p-3 rounded text-white" value={email} onChange={e => setEmail(e.target.value)} />
            <input type="password" placeholder="Senha" className="w-full bg-zinc-950 border border-zinc-800 p-3 rounded text-white" value={password} onChange={e => setPassword(e.target.value)} />

            {isRegistering ? (
                <button onClick={handleRegister} className="w-full bg-red-600 hover:bg-red-700 text-white font-bold py-3 rounded uppercase">Solicitar Acesso</button>
            ) : (
                <button onClick={handleLogin} className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-3 rounded uppercase">Entrar no Combate</button>
            )}

            <button onClick={() => setIsRegistering(!isRegistering)} className="w-full text-zinc-500 text-sm hover:text-white mt-2">
                {isRegistering ? "Já tenho conta" : "Solicitar Recrutamento"}
            </button>
        </div>
      </div>
    </div>
  );
};

