      { id: 'mentoria', label: 'Mentoria Tática', icon: Brain, role: 'ALL' },
      { id: 'questoes', label: 'Campo de Tiro', icon: Crosshair, role: 'ALL' },
      { id: 'redacao', label: 'Redação', icon: PenTool, role: 'ALL' },
      ...(isAdmin ? [
          { id: 'users', label: 'Tropa (Usuários)', icon: Users, role: 'ADMIN' },
          { id: 'admin_questoes', label: 'Gestão Questões', icon: Settings, role: 'ADMIN' }
      ] : [])
  ];

  return (
    <div className="flex min-h-screen bg-[#09090b] text-zinc-200 font-sans">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-zinc-950 border-r border-zinc-900 transform transition-transform duration-300 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0`}>
        <div className="p-6 border-b border-zinc-900 flex justify-between items-center">
            <h1 className="text-xl font-black text-white uppercase">Sangue <span className="text-red-600">Milico</span></h1>
            <button onClick={() => setSidebarOpen(false)} className="md:hidden text-zinc-500"><X size={24}/></button>
        </div>

        <div className="p-4 space-y-1">
            {navItems.filter(i => i.role === 'ALL' || i.role === currentUser.role).map(item => (
                <button
                    key={item.id}
                    onClick={() => { setActiveTab(item.id); setSidebarOpen(false); }}
                    className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg text-sm font-bold uppercase tracking-wide transition-colors ${activeTab === item.id ? 'bg-red-600 text-white shadow-lg shadow-red-900/20' : 'text-zinc-500 hover:text-white hover:bg-zinc-900'}`}
                >
                    <item.icon size={18} />
                    {item.label}
                </button>
            ))}
        </div>

        <div className="absolute bottom-0 left-0 right-0 p-4 border-t border-zinc-900">
            <div className="flex items-center gap-3 mb-4 px-2">
                <div className="w-8 h-8 rounded-full bg-zinc-800 flex items-center justify-center font-bold text-xs">{currentUser.name.charAt(0)}</div>
                <div className="overflow-hidden">
                    <p className="text-sm font-bold text-white truncate">{currentUser.name}</p>
                    <p className="text-[10px] text-zinc-500 uppercase">{currentUser.role === UserRole.ADMIN ? 'Comandante' : 'Recruta'}</p>
                </div>
            </div>
            <button onClick={handleLogout} className="w-full flex items-center gap-2 text-zinc-500 hover:text-red-500 text-xs font-bold uppercase px-2 py-2">
                <LogOut size={16} /> Desmobilizar (Sair)
            </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:ml-64 p-4 md:p-8 overflow-y-auto">
        {/* Mobile Header */}
        <div className="md:hidden flex justify-between items-center mb-6">
            <button onClick={() => setSidebarOpen(true)} className="text-white"><Menu size={24}/></button>
            <h1 className="text-lg font-black text-white uppercase">Sangue <span className="text-red-600">Milico</span></h1>
            <div className="w-8"></div>
        </div>

        {activeTab === 'dashboard' && (
            <div className="animate-fade-in">
                <h2 className="text-2xl font-bold text-white mb-4">Painel Geral</h2>
                <div className="p-6 bg-zinc-900 rounded-xl border border-zinc-800">
                    <p className="text-zinc-400">Bem-vindo, {currentUser.name}. Selecione uma missão no menu lateral.</p>
                </div>
            </div>
        )}

        {activeTab === 'trilha' && <TrilhaVencedor />}

        {activeTab === 'mentoria' && (
            isAdmin ? <AdminMentorshipPanel users={users} plans={plans} /> : <StudentMentorshipPanel studentId={currentUser.id} />
        )}

        {activeTab === 'questoes' && <QuestionBankPanel studentId={currentUser.id} />}

        {activeTab === 'redacao' && <EssayPanel user={currentUser} hasPremium={true} />}

        {activeTab === 'admin_questoes' && isAdmin && <AdminQuestionManager />}

        {/* --- USERS TAB (FROM SNIPPET) --- */}
        {activeTab === 'users' && isAdmin && (
            <div className="space-y-8 animate-fade-in">
                {/* Cadastro de Novo Aluno */}
                <div className="bg-white dark:bg-zinc-900 p-6 rounded-xl border border-zinc-200 dark:border-zinc-800 shadow-lg">
                    <h3 className="text-xl font-bold dark:text-white mb-4 flex items-center gap-2">
                        <Plus className="text-green-500"/> Cadastrar Novo Combatente
                    </h3>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end">
                        <div>
                            <label className="text-xs font-bold text-zinc-500 uppercase">Nome Completo</label>
                            <input type="text" value={newUserName} onChange={e => setNewUserName(e.target.value)} className="w-full mt-1 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 p-2.5 rounded-lg text-zinc-800 dark:text-white outline-none focus:border-green-600" />
                        </div>
                        <div>
                            <label className="text-xs font-bold text-zinc-500 uppercase">E-mail</label>
                            <input type="email" value={newUserEmail} onChange={e => setNewUserEmail(e.target.value)} className="w-full mt-1 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 p-2.5 rounded-lg text-zinc-800 dark:text-white outline-none focus:border-green-600" />
                        </div>
                        <div>
                            <label className="text-xs font-bold text-zinc-500 uppercase">Senha</label>
                            <input type="text" value={newUserPass} onChange={e => setNewUserPass(e.target.value)} className="w-full mt-1 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 p-2.5 rounded-lg text-zinc-800 dark:text-white outline-none focus:border-green-600" />
                        </div>
                        <div>
                            <label className="text-xs font-bold text-zinc-500 uppercase">Plano Inicial</label>
                            <select value={newUserPlan} onChange={e => setNewUserPlan(e.target.value)} className="w-full mt-1 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 p-2.5 rounded-lg text-zinc-800 dark:text-white outline-none focus:border-green-600">
                                <option value="">Sem Plano (Global)</option>
                                {plans.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                            </select>
                        </div>
                    </div>
                    <button onClick={handleCreateUser} className="mt-4 bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-6 rounded-lg w-full md:w-auto shadow-lg transition">
                        Cadastrar Aluno
                    </button>
                </div>

                {/* Solicitações Pendentes */}
                {pendingUsers.length > 0 && (
                    <div className="bg-red-900/10 border border-red-900/30 p-6 rounded-xl animate-pulse">
                        <h3 className="text-xl font-bold text-red-500 mb-4 flex items-center gap-2">
                            <ShieldAlert/> Solicitações de Acesso ({pendingUsers.length})
                        </h3>
                        <div className="space-y-3">
                            {pendingUsers.map(u => (
                                <div key={u.id} className="flex flex-col md:flex-row md:items-center justify-between bg-zinc-950 p-4 rounded-lg border border-red-900/30 gap-4">
                                    <div>
                                        <p className="font-bold text-white text-lg">{u.name}</p>
                                        <p className="text-zinc-400 text-sm">{u.email}</p>
                                        <p className="text-xs text-red-400 mt-1">Aguardando aprovação</p>
                                    </div>
                                    <div className="flex gap-2">
                                        <button onClick={() => handleApproveUser(u.id)} className="bg-green-600 hover:bg-green-700 text-white px-4 py-2 rounded font-bold transition shadow-lg">Aprovar</button>
                                        <button onClick={() => handleRejectUser(u.id)} className="bg-red-600 hover:bg-red-700 text-white px-4 py-2 rounded font-bold transition shadow-lg">Rejeitar</button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Lista de Alunos Ativos */}
                <div className="bg-white dark:bg-zinc-900 p-6 rounded-xl border border-zinc-200 dark:border-zinc-800">
                    <div className="flex justify-between items-center mb-6">
                        <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
                            <Users className="text-blue-500"/> Tropa Ativa ({activeUsers.length})
                        </h3>
                    </div>

                    <div className="grid grid-cols-1 gap-4">
                        {activeUsers.map(u => (
                            <div key={u.id} className="flex flex-col md:flex-row md:items-center justify-between bg-zinc-50 dark:bg-zinc-950 p-4 rounded-lg border border-zinc-200 dark:border-zinc-800 hover:border-zinc-400 dark:hover:border-zinc-600 transition group">
                                <div className="flex items-center gap-4 mb-4 md:mb-0">
                                    <div className="w-12 h-12 bg-zinc-200 dark:bg-zinc-800 rounded-full flex items-center justify-center text-zinc-500 dark:text-zinc-400 font-bold text-xl border border-zinc-300 dark:border-zinc-700">
                                        {u.name.charAt(0)}
                                    </div>
                                    <div>
                                        <p className="font-bold text-zinc-800 dark:text-white text-lg">{u.name}</p>
                                        <p className="text-zinc-500 text-sm">{u.email}</p>
                                        <div className="flex items-center gap-2 mt-1">
                                            <span className="text-[10px] bg-green-100 dark:bg-green-900/30 text-green-600 dark:text-green-400 px-2 py-0.5 rounded font-bold border border-green-200 dark:border-green-900">APROVADO</span>
                                            {u.lastStudyDate && <span className="text-[10px] text-zinc-500">Último acesso: {new Date(u.lastStudyDate).toLocaleDateString()}</span>}
                                        </div>
                                    </div>
                                </div>

                                <div className="flex flex-col md:flex-row items-center gap-4">
                                    <div className="w-full md:w-auto">
                                        <label className="text-[10px] font-bold text-zinc-500 uppercase block mb-1">Plano Atual</label>
                                        <select 
                                            value={u.planId || ""} 
                                            onChange={(e) => handleChangeUserPlan(u.id, e.target.value)}
                                            className="w-full md:w-40 bg-white dark:bg-zinc-900 border border-zinc-300 dark:border-zinc-700 text-zinc-800 dark:text-white text-sm p-2 rounded outline-none focus:border-blue-500"
                                        >
                                            <option value="">Global (Sem Plano)</option>
                                            {plans.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                                        </select>
                                    </div>

                                    <div className="flex gap-2 w-full md:w-auto">
                                        <button 
                                            onClick={() => setViewingStudentId(u.id)}
                                            className="flex-1 md:flex-none bg-blue-600 hover:bg-blue-700 text-white px-3 py-2 rounded text-sm font-bold flex items-center justify-center gap-2 transition"
                                            title="Ver Painel do Aluno"
                                        >
                                            <Eye size={16}/> Acessar
                                        </button>
                                        <button 
                                            onClick={() => handleRejectUser(u.id)} 
                                            className="flex-1 md:flex-none bg-red-600 hover:bg-red-700 text-white px-3 py-2 rounded text-sm font-bold flex items-center justify-center gap-2 transition"
                                            title="Excluir Aluno"
                                        >
                                            <Trash2 size={16}/>
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                        {activeUsers.length === 0 && <p className="text-center text-zinc-500 py-8 italic">Nenhum aluno ativo no momento.</p>}
                    </div>
                </div>
            </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect, useMemo } from 'react';
import { 
  LayoutDashboard, BookOpen, Users, Settings, LogOut, 
  Edit3, Plus, Save, FileText, Video, List as ListIcon, 
  Lock, ChevronDown, ChevronRight, Trash2, ShieldAlert, Eye, 
  Menu, X
} from 'lucide-react';
import { User, Material, Plan, UserRole } from './types';
import { globalRepo } from './services/repository';

// Components
import { StudentMentorshipPanel } from './mentoria-individual/StudentPanel';
import { AdminMentorshipPanel } from './mentoria-individual/AdminPanel';

// Stub for RichTextEditor if not present
const RichTextEditor = ({ value, onChange }: { value: string, onChange: (val: string) => void }) => {
    return (
        <textarea 
            className="w-full h-32 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 rounded p-2 text-zinc-800 dark:text-white"
            value={value}
            onChange={(e) => onChange(e.target.value)}
        />
    );
};

export default function App() {
  // Global Data
  const [users, setUsers] = useState<User[]>([]);
  const [materials, setMaterials] = useState<Material[]>([]);
  const [plans, setPlans] = useState<Plan[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  // Navigation
  const [activeTab, setActiveTab] = useState('materials');
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [viewingStudentId, setViewingStudentId] = useState<string | null>(null);

  // Material Form
  const [editingMaterialId, setEditingMaterialId] = useState<string | null>(null);
  const [newMatTitle, setNewMatTitle] = useState('');
  const [newMatSubject, setNewMatSubject] = useState('');
  const [newMatTopic, setNewMatTopic] = useState('');
  const [newMatCategory, setNewMatCategory] = useState<'GUIDED' | 'LEI_SECA'>('GUIDED');
  const [newMatContent, setNewMatContent] = useState('');
  const [newMatPdf, setNewMatPdf] = useState('');
  const [newMatVideo, setNewMatVideo] = useState('');
  const [newMatQuestions, setNewMatQuestions] = useState('');
  const [matAllowedPlans, setMatAllowedPlans] = useState<string[]>([]);
  const [expandedSubjects, setExpandedSubjects] = useState<string[]>([]);

  // User Form
  const [newUserName, setNewUserName] = useState('');
  const [newUserEmail, setNewUserEmail] = useState('');
  const [newUserPass, setNewUserPass] = useState('');
  const [newUserPlan, setNewUserPlan] = useState('');

  // Initial Load
  useEffect(() => {
    loadData();
    // Mock Auth
    const u = localStorage.getItem('current_user');
    if (u) setCurrentUser(JSON.parse(u));
    else {
        // Create a dummy admin for dev
        const admin: User = { id: 'admin', name: 'Admin', email: 'admin@test.com', role: UserRole.ADMIN, approved: true, achievements: [] };
        setCurrentUser(admin);
        localStorage.setItem('current_user', JSON.stringify(admin));
    }
  }, []);

  const loadData = async () => {
      setUsers(await globalRepo.getUsers());
      setMaterials(await globalRepo.getMaterials());
      setPlans(await globalRepo.getPlans());
  };

  // Computed
  const materialsBySubject = useMemo(() => {
    const groups: Record<string, Material[]> = {};
    materials.forEach(m => {
        if (!groups[m.subject]) groups[m.subject] = [];
        groups[m.subject].push(m);
    });
    return groups;
  }, [materials]);

  const sortedSubjects = Object.keys(materialsBySubject).sort();
  const pendingUsers = users.filter(u => !u.approved);
  const activeUsers = users.filter(u => u.approved);

  // Handlers
  const handleSaveMaterial = async () => {
      const mat: Material = {
          id: editingMaterialId || Date.now().toString(),
          title: newMatTitle,
          subject: newMatSubject,
          topic: newMatTopic,
          category: newMatCategory,
          contentHtml: newMatContent,
          pdfUrl: newMatPdf,
          videoUrl: newMatVideo,
          questionsUrl: newMatQuestions,
          allowedPlanIds: matAllowedPlans,
          dateAdded: new Date().toISOString(),
          order: 0 // logic for order
      };
      // Optimistic update
      const newMats = editingMaterialId 
        ? materials.map(m => m.id === mat.id ? mat : m)
        : [...materials, mat];

      setMaterials(newMats);
      await globalRepo.saveMaterials(newMats); // This saves ALL, inefficient but matches repo
      handleCancelMaterialEdit();
  };

  const handleEditMaterial = (mat: Material) => {
      setEditingMaterialId(mat.id);
      setNewMatTitle(mat.title);
      setNewMatSubject(mat.subject);
      setNewMatTopic(mat.topic || '');
      setNewMatCategory(mat.category);
      setNewMatContent(mat.contentHtml);
      setNewMatPdf(mat.pdfUrl || '');
      setNewMatVideo(mat.videoUrl || '');
      setNewMatQuestions(mat.questionsUrl || '');
      setMatAllowedPlans(mat.allowedPlanIds || []);
  };

  const handleCancelMaterialEdit = () => {
      setEditingMaterialId(null);
      setNewMatTitle('');
      setNewMatSubject('');
      setNewMatTopic('');
      setNewMatCategory('GUIDED');
      setNewMatContent('');
      setNewMatPdf('');
      setNewMatVideo('');
      setNewMatQuestions('');
      setMatAllowedPlans([]);
  };

  const handleDeleteMaterial = async (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      if(!confirm('Delete?')) return;
      await globalRepo.deleteMaterial(id);
      setMaterials(materials.filter(m => m.id !== id));
  };

  const toggleAllowedPlan = (planId: string, current: string[], setFn: any) => {
      if (current.includes(planId)) setFn(current.filter(id => id !== planId));
      else setFn([...current, planId]);
  };

  const toggleSubjectExpand = (sub: string) => {
      if (expandedSubjects.includes(sub)) setExpandedSubjects(expandedSubjects.filter(s => s !== sub));
      else setExpandedSubjects([...expandedSubjects, sub]);
  };

  const handleMoveMaterial = (mat: Material, direction: 'up' | 'down') => {
      // Implementation skipped for brevity, just needs to exist
      console.log('move', mat, direction);
  };

  const getSubjectIcon = (subject: string, className: string) => {
      return <BookOpen className={className} size={20} />;
  };

  const handleSubjectVisibilityChange = (subject: string, planId: string, isChecked: boolean) => {
      const subjectMaterials = materialsBySubject[subject];
      const updatedMaterials = materials.map(m => {
          if (m.subject === subject) {
              const currentPlans = m.allowedPlanIds || [];
              let newPlans = [];
              if (isChecked) newPlans = [...new Set([...currentPlans, planId])];
              else newPlans = currentPlans.filter(p => p !== planId);
              return { ...m, allowedPlanIds: newPlans };
          }
          return m;
      });
      setMaterials(updatedMaterials);
      globalRepo.saveMaterials(updatedMaterials);
  };

  const handleCreateUser = async () => {
      if(!newUserName || !newUserEmail) return;
      const u: User = {
          id: Date.now().toString(),
          name: newUserName,
          email: newUserEmail,
          password: newUserPass,
          role: UserRole.STUDENT,
          approved: true,
          achievements: [],
          planId: newUserPlan || undefined
      };
      await globalRepo.saveUser(u);
      setUsers([...users, u]);
      setNewUserName(''); setNewUserEmail(''); setNewUserPass(''); setNewUserPlan('');
  };

  const handleApproveUser = async (id: string) => {
      const user = users.find(u => u.id === id);
      if(user) {
          const updated = { ...user, approved: true };
          await globalRepo.saveUser(updated);
          setUsers(users.map(u => u.id === id ? updated : u));
      }
  };

  const handleRejectUser = async (id: string) => {
      await globalRepo.deleteUser(id);
      setUsers(users.filter(u => u.id !== id));
  };

  const handleChangeUserPlan = async (userId: string, planId: string) => {
      const user = users.find(u => u.id === userId);
      if(user) {
          const updated = { ...user, planId: planId || undefined };
          await globalRepo.saveUser(updated);
          setUsers(users.map(u => u.id === userId ? updated : u));
      }
  };

  // Render Logic
  if (viewingStudentId) {
      return (
          <div className="relative">
              <button 
                onClick={() => setViewingStudentId(null)}
                className="fixed top-4 right-4 z-50 bg-zinc-800 text-white px-4 py-2 rounded shadow-lg font-bold"
              >
                Voltar ao Admin
              </button>
              <StudentMentorshipPanel studentId={viewingStudentId} />
          </div>
      );
  }

  return (
    <div className="flex min-h-screen bg-zinc-50 dark:bg-zinc-950 text-zinc-900 dark:text-zinc-100 font-sans">
        {/* Sidebar */}
        <aside className={`${sidebarOpen ? 'w-64' : 'w-20'} bg-white dark:bg-zinc-900 border-r border-zinc-200 dark:border-zinc-800 transition-all duration-300 flex flex-col fixed h-full z-10`}>
            <div className="p-4 flex items-center justify-between border-b border-zinc-200 dark:border-zinc-800">
                {sidebarOpen && <span className="font-black text-xl tracking-tighter uppercase">Sangue<span className="text-red-600">Milico</span></span>}
                <button onClick={() => setSidebarOpen(!sidebarOpen)} className="p-2 hover:bg-zinc-100 dark:hover:bg-zinc-800 rounded">
                    <Menu size={20} />
                </button>
            </div>

            <div className="flex-1 py-4 space-y-2 px-2">
                {[
                    { id: 'materials', icon: BookOpen, label: 'Materiais' },
                    { id: 'users', icon: Users, label: 'Combatentes' },
                ].map(item => (
                    <button 
                        key={item.id}
                        onClick={() => setActiveTab(item.id)}
                        className={`w-full flex items-center gap-3 p-3 rounded-lg transition-colors ${activeTab === item.id ? 'bg-red-600 text-white' : 'text-zinc-600 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-zinc-800'}`}
                    >
                        <item.icon size={20} />
                        {sidebarOpen && <span className="font-bold text-sm">{item.label}</span>}
                    </button>
                ))}
            </div>
        </aside>

        {/* Main Content */}
        <div className={`flex-1 transition-all duration-300 ${sidebarOpen ? 'ml-64' : 'ml-20'} p-8`}>
            <div className="max-w-6xl mx-auto">
                {/* Content injected from the fragment */}
                {activeTab === 'materials' && (
                    <div className="space-y-8 animate-fade-in">
                        {/* Material Form */}
                        <div className="bg-white dark:bg-zinc-900 p-6 rounded-xl border border-zinc-200 dark:border-zinc-800 shadow-lg">
                            <div className="flex justify-between items-center mb-6">
                                <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
                                    {editingMaterialId ? <Edit3 size={24} className="text-blue-500"/> : <Plus size={24} className="text-green-500"/>} 
                                    {editingMaterialId ? 'Editar Material' : 'Adicionar Novo Material'}
                                </h3>
                                {editingMaterialId && <button onClick={handleCancelMaterialEdit} className="text-zinc-500 hover:text-red-500 text-sm underline">Cancelar Edição</button>}
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
                                <div className="col-span-2 md:col-span-1">
                                    <label className="text-xs font-bold text-zinc-500 uppercase">Título</label>
                                    <input value={newMatTitle} onChange={e => setNewMatTitle(e.target.value)} placeholder="Ex: Resumo de Crase" className="w-full mt-1 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 p-2.5 rounded-lg text-zinc-800 dark:text-white outline-none focus:border-red-600" />
                                </div>
                                <div className="col-span-2 md:col-span-1">
                                    <label className="text-xs font-bold text-zinc-500 uppercase">Matéria (Pasta)</label>
                                    <input value={newMatSubject} onChange={e => setNewMatSubject(e.target.value)} placeholder="Ex: Português" className="w-full mt-1 bg-zinc-50 dark:bg-zinc-800 border border-zinc-300 dark:border-zinc-700 p-2.5 rounded-lg text-zinc-800 dark:text-white outline-none focus:border-red-600" />
                                </div>
